PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE IF NOT EXISTS "aircraft_seen" (
  hex           TEXT NOT NULL,
  registration  TEXT,
  type          TEXT,
  flight        TEXT,
  seen_date     TEXT NOT NULL, operator TEXT, origin TEXT, destination TEXT, enriched INTEGER DEFAULT 0, confidence TEXT, owner TEXT, airline TEXT,
  PRIMARY KEY (hex, seen_date)
);
CREATE INDEX idx_seen_date ON aircraft_seen(seen_date);
CREATE INDEX idx_type ON aircraft_seen(type);
CREATE INDEX idx_registration ON aircraft_seen(registration);
